from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent, single‑sentence description from a list of triples."""
    if not triples:
        return ""

    # Group triples by their subject so we can create relative clauses when needed
    subjects: dict[str, dict[str, str]] = {}
    for t in triples:
        subjects.setdefault(t.subject, {})[t.predicate] = t.object

    # Helper to format a list with commas and "and"
    def fmt_list(items: list[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Build clause for each subject
    clauses: list[str] = []
    main_subject = triples[0].subject  # the first subject will be the main focus

    for subj, info in subjects.items():
        # start clause
        if subj == main_subject:
            clause_parts: list[str] = []
            # identification
            if "category" in info:
                clause_parts.append(f"{subj} is a {info['category']}")
            else:
                clause_parts.append(f"{subj} is a monument")

            # location hierarchy (municipality → district → state → country)
            loc_parts = [info[k] for k in ("municipality", "district", "location", "state", "country") if k in info]
            if loc_parts:
                clause_parts.append(f"located in {fmt_list(loc_parts)}")

            # dates
            date_phrases = {
                "established": "established on",
                "foundingDate": "founded on",
                "inaugurationDate": "inaugurated on",
            }
            for pred, phr in date_phrases.items():
                if pred in info:
                    clause_parts.append(f"{phr} {info[pred]}")

            # dedicated, designer, material, ownership
            if "dedicatedTo" in info:
                clause_parts.append(f"dedicated to {info['dedicatedTo']}")
            if "designer" in info:
                clause_parts.append(f"designed by {info['designer']}")
            if "material" in info:
                clause_parts.append(f"made of {info['material']}")
            if "owner" in info:
                clause_parts.append(f"owned by {info['owner']}")
            elif "owningOrganisation" in info:
                clause_parts.append(f"owned by {info['owningOrganisation']}")

            # other entity‑type predicates (capital, legislature, leader, etc.)
            if "capital" in info:
                clause_parts.append(f"the capital is {info['capital']}")
            if "legislature" in info:
                clause_parts.append(f"its legislature is {info['legislature']}")
            if "leader" in info:
                title = info.get("leaderTitle", "")
                clause_parts.append(f"led by {title + ' ' if title else ''}{info['leader']}".strip())
            if "currency" in info:
                clause_parts.append(f"currency is the {info['currency']}")
            if "largestCity" in info:
                clause_parts.append(f"largest city is {info['largestCity']}")
            if "ethnicGroup" in info:
                clause_parts.append(f"ethnic group includes {info['ethnicGroup']}")
            if "language" in info:
                clause_parts.append(f"language spoken is {info['language']}")
            if "religion" in info:
                clause_parts.append(f"religion is {info['religion']}")
            if "nativeName" in info:
                clause_parts.append(f"its native name is {info['nativeName']}")

            clauses.append(", ".join(clause_parts))
        else:
            # secondary subjects become relative clauses attached to the main one
            rel_parts: list[str] = []
            if "nearestCity" in info:
                rel_parts.append(f"nearest city is {info['nearestCity']}")
            if "hasToItsNorth" in info:
                rel_parts.append(f"has to its north {info['hasToItsNorth']}")
            if "hasToItsSouthwest" in info:
                rel_parts.append(f"has to its southwest {info['hasToItsSouthwest']}")
            if "hasToItsWest" in info:
                rel_parts.append(f"has to its west {info['hasToItsWest']}")
            if "hasToItsSoutheast" in info:
                rel_parts.append(f"has to its southeast {info['hasToItsSoutheast']}")

            if rel_parts:
                # attach as a relative clause
                clauses.append(f"{subj}, which {'; '.join(rel_parts)}")

    # Join main clause with secondary relative clauses using commas and "and"
    sentence = fmt_list(clauses) + "."
    return sentence

# EVOLVE-BLOCK-END

